class Solution:
    def minTaps(self, n, ranges):
        # DP: dp[i] = min taps to water [0, i]
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[0] = 0
        for i in range(n + 1):
            l = max(0, i - ranges[i])
            r = min(n, i + ranges[i])
            for j in range(l, r + 1):
                if dp[l] < INF:
                    dp[r] = min(dp[r], dp[l] + 1)
        return dp[n] if dp[n] < INF else -1

