class Solution:
    def minTaps(self, n, ranges):
        reach = [0] * (n + 1)
        for i in range(n + 1):
            l = max(0, i - ranges[i])
            reach[l] = max(reach[l], i + ranges[i])
        taps = 0
        cur_end = 0
        farthest = 0
        for i in range(n):
            farthest = max(farthest, reach[i])
            if i == cur_end:
                if farthest <= cur_end:
                    return -1
                taps += 1
                cur_end = farthest
                if cur_end >= n:
                    break
        return taps

