var minTaps = function(n, ranges) {
    const reach = new Array(n + 1).fill(0);
    for (let i = 0; i <= n; i++) {
        const l = Math.max(0, i - ranges[i]);
        reach[l] = Math.max(reach[l], i + ranges[i]);
    }
    let taps = 0, curEnd = 0, farthest = 0;
    for (let i = 0; i < n; i++) {
        farthest = Math.max(farthest, reach[i]);
        if (i === curEnd) {
            if (farthest <= curEnd) return -1;
            taps++;
            curEnd = farthest;
            if (curEnd >= n) break;
        }
    }
    return taps;
};
